update menu_image set
		is_primary= TRUE
where menu_image_idx = #{menuImageIdx} and menu_idx = #{menuIdx}

update menu_image set
		is_primary= FALSE
where menu_image_idx = #{menuImageIdx} and menu_idx = #{menuIdx}

update menu_image set
		image_url = #{imageUrl},
		is_primary = #{isPrimary},
		display_order= #{displayOrder}
where menu_image_idx = #{menuImageIdx} and menu_idx = #{menuIdx}
